sql:
SELECT * 
FROM report_outputs 
WHERE output_type = 'PDF';

SELECT DISTINCT company_id
FROM financial_statements
WHERE statement_id IN (SELECT statement_id FROM employee_share_schemes);

SELECT comprehensive_income.*
FROM comprehensive_income
WHERE comprehensive_income.date = '2022-01-01';

SELECT financial_year, COUNT(statement_id) AS NumberOfStatements
FROM financial_statements
GROUP BY financial_year;

SELECT statement_type, financial_year, currency, company_id, reporting_period_start, reporting_period_end, status, created_at, updated_at
FROM financial_statements
WHERE statement_id = 1;

SELECT statement_id, COUNT(*) as num_new_share_issues
FROM new_share_issues
GROUP BY statement_id;

SELECT ACOS(AVG(amount))
FROM comprehensive_income
WHERE statement_id = 0;

external_knowledge:
- Total changes in equity: Sum of all changes in equity values for a statement;
- Total called-up share capital: Sum of all called-up share capital values for a statement;
- Financial statements: Records of a company’s financial activities, including income statements, balance sheets, and cash flow statements.

